mapper.select:
SELECT hfc.id, hfc.hq_company_id AS hqCompanyId, hfc.first_company_id AS firstCompanyId, hfc.region_id AS regionId, hq.company_name AS hqCompanyName, fc.company_name AS firstCompanyName, r.region_name AS regionName, hfc.contract_no AS contractNo, hfc.status, hfc.remark, hfc.create_time AS contractTime, hfc.create_time AS createTime FROM hq_first_contract hfc LEFT JOIN sys_company hq ON hfc.hq_company_id = hq.id LEFT JOIN sys_company fc ON hfc.first_company_id = fc.id LEFT JOIN sys_region r ON hfc.region_id = r.id
AND hfc.hq_company_id = #{query.hqCompanyId}
AND hfc.first_company_id = #{query.firstCompanyId}
AND hfc.region_id = #{query.regionId}
ORDER BY hfc.id DESC
